#include<bits/stdc++.h>
using namespace std;
int p[1010],v[1010];
double dp[110][40010];
int flag[110][40010];
int main()
{
    int k,n;
    scanf("%d%d",&k,&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&p[i]);
        int c;
        scanf("%d",&c);
        while(c!=0)
        {
            v[i]|=(1<<(c-1));
            scanf("%d",&c);
        }
    }
    for(int i=k;i>=1;i--)
    {
        for(int j=0;j<(1<<n);j++)
        {
            for(int l=1;l<=n;l++)
            {
                if((j&v[l])==v[l])
                {
                    dp[i][j]+=max(dp[i+1][j],dp[i+1][j|(1<<(l-1))]+p[l]);
                }
                else
                {
                    dp[i][j]+=dp[i+1][j];
                }
            }
            dp[i][j]/=n;
        }
    }
    printf("%.6lf",dp[1][0]);
    return 0;
}
